import{_ as o,o as a,c as d,ag as i}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Аліаси діагностики | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди перевірки стану. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси діагностики | Dotfiles","description":"Короткі команди перевірки стану. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси діагностики | Dotfiles preview","canonical":"/uk/aliases/diagnostics/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси діагностики","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/diagnostics/"},"headers":[],"relativePath":"uk/aliases/diagnostics/index.md","filePath":"uk/aliases/diagnostics/index.md","lastUpdated":1773010926000}'),t={name:"uk/aliases/diagnostics/index.md"};function c(l,e,s,r,n,p){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="аліаси-діагностики" tabindex="-1">Аліаси діагностики <a class="header-anchor" href="#аліаси-діагностики" aria-label="Permalink to &quot;Аліаси діагностики&quot;">​</a></h1><p>Короткі команди перевірки стану.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 14</li><li>Допоміжні функції: 1</li><li>Файли джерел: 1</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>ca</code> → <code>chezmoi apply</code></li><li><code>capply</code> → <code>dot apply</code></li><li><code>cdiff</code> → <code>dot diff</code></li><li><code>cdrift</code> → <code>dot drift</code></li><li><code>ce</code> → <code>chezmoi edit</code></li><li><code>crem</code> → <code>dot remove</code></li><li><code>cupdate</code> → <code>dot update</code></li><li><code>dot-doctor</code> → <code>dotdoc</code></li><li><code>dot-drift</code> → <code>drift</code></li><li><code>dot-heal</code> → <code>heal</code></li><li><code>dotdoc</code> → <code>bash $HOME/.dotfiles/scripts/diagnostics/doctor.sh</code></li><li><code>dotdoc-full</code> → <code>bash $HOME/.dotfiles/scripts/diagnostics/doctor.sh &amp;&amp; echo &quot;\\n--- Path Info ---&quot; &amp;&amp; echo $PATH | tr &quot;:&quot; &quot;\\n&quot; | glow -</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const f=o(t,[["render",c]]);export{h as __pageData,f as default};
